        | RawKind::InternalKeyword
        | RawKind::KeyKeyword
        | RawKind::KeysKeyword
        | RawKind::LabelsKeyword
        | RawKind::LayoutKeyword
        | RawKind::LocalKeyword
        | RawKind::MultilineComment
        | RawKind::NamespaceKeyword
        | RawKind::ObjectTypeKeyword
        | RawKind::OfKeyword
        | RawKind::PageKeyword
        | RawKind::PagecustomizationKeyword
        | RawKind::PageextensionKeyword
        | RawKind::PartKeyword
        | RawKind::PermissionsetKeyword
        | RawKind::PermissionsetextensionKeyword
        | RawKind::ProcedureKeyword
        | RawKind::ProfileKeyword
        | RawKind::ProfileextensionKeyword
        | RawKind::ProtectedKeyword
        | RawKind::QueryKeyword
        | RawKind::RenderingKeyword
        | RawKind::RepeatKeyword
        | RawKind::RepeaterKeyword
        | RawKind::ReportKeyword
        | RawKind::ReportextensionKeyword
        | RawKind::RequestpageKeyword
        | RawKind::SchemaKeyword
        | RawKind::SystempartKeyword
        | RawKind::TableKeyword
